#include <bits/stdc++.h>
using namespace std;

const int N=5010;

int n,m;
int head[N],ver[4*N],nxt[4*N],tot=1;
int dfn[N],low[N],num,c[N],cnt,d[N];
bool b[4*N];

void add(int x,int y){
    ver[++tot]=y,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,nxt[tot]=head[y],head[y]=tot;
}

void tarjan(int x,int ine){
    dfn[x]=low[x]=++num;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y,i);
            low[x]=min(low[x],low[y]);
            if(low[y]>dfn[x])
                b[i]=b[i^1]=1;
        }else if((i^1)!=ine)
            low[x]=min(low[x],dfn[y]);
}

void dfs(int x){
    c[x]=cnt;
    for(int i=head[x];i;i=nxt[i]){
        if(!b[i] && !c[ver[i]])
            dfs(ver[i]);
        else if(c[ver[i]] && b[i])
            d[c[ver[i]]]++,d[cnt]++;
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    tarjan(1,0);
    for(int i=1;i<=n;i++)
        if(!c[i]){
            cnt++;
            dfs(i);
        }
    int ans=0;
    for(int i=1;i<=cnt;i++)
        if(d[i]==1)
            ans++;
    printf("%d",(ans+1)/2);
    return 0;
}
